CREATE TABLE IF NOT EXISTS users (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), username VARCHAR(50) UNIQUE NOT NULL, display_name VARCHAR(100) NOT NULL, email VARCHAR(255) UNIQUE NOT NULL, password_hash VARCHAR(255) NOT NULL, avatar_url TEXT, bio TEXT DEFAULT '', city VARCHAR(100) DEFAULT '', age INTEGER, occupation VARCHAR(100) DEFAULT '', interests TEXT[] DEFAULT '{}', agent_name VARCHAR(100) DEFAULT 'Мой агент', is_online BOOLEAN DEFAULT false, last_seen TIMESTAMPTZ DEFAULT NOW(), created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());